import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { useTexture } from '@react-three/drei';
import * as THREE from 'three';

// ─────────────────────────────────────────────
// SATURN RING PARTICLES
// Dense cloud of small glowing rocks orbiting the heart
// ─────────────────────────────────────────────
function SaturnRing({ innerRadius, outerRadius, tiltX, tiltZ, particleCount, color }) {
  const pointsRef = useRef();

  const { positions, sizes } = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    const siz = new Float32Array(particleCount);
    for (let i = 0; i < particleCount; i++) {
      // Random angle and radius within the band
      const angle = Math.random() * Math.PI * 2;
      const r = innerRadius + Math.random() * (outerRadius - innerRadius);
      const thickness = (Math.random() - 0.5) * 0.25; // thin disc

      const x = Math.cos(angle) * r;
      const z = Math.sin(angle) * r;

      // Apply ring tilt
      const cosX = Math.cos(tiltX), sinX = Math.sin(tiltX);
      const cosZ = Math.cos(tiltZ), sinZ = Math.sin(tiltZ);
      pos[i * 3 + 0] = x * cosZ - z * sinZ;
      pos[i * 3 + 1] = (x * sinZ + z * cosZ) * sinX + thickness;
      pos[i * 3 + 2] = (x * sinZ + z * cosZ) * cosX;

      siz[i] = 0.04 + Math.random() * 0.08;
    }
    return { positions: pos, sizes: siz };
  }, [innerRadius, outerRadius, tiltX, tiltZ, particleCount]);

  useFrame((state) => {
    if (pointsRef.current) {
      // Slowly orbit the entire ring
      pointsRef.current.rotation.y += 0.0015;
    }
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" count={particleCount} array={positions} itemSize={3} />
        <bufferAttribute attach="attributes-size" count={particleCount} array={sizes} itemSize={1} />
      </bufferGeometry>
      <pointsMaterial
        color={color}
        size={0.12}
        sizeAttenuation
        transparent
        opacity={0.75}
      />
    </points>
  );
}

// ─────────────────────────────────────────────
// PHOTO ORBITAL — floats just above the ring plane
// ─────────────────────────────────────────────

// Ring config: photos orbit ON TOP of the particle rings
const PHOTO_RINGS = [
  { count: 8,  radius: 5.8,  tiltX: 0.18,  tiltZ: 0.0,   speed: 0.22, yLift: 0.45 },
  { count: 10, radius: 8.0,  tiltX: 0.18,  tiltZ: 0.05,  speed: 0.15, yLift: 0.45 },
  { count: 12, radius: 10.5, tiltX: 0.18,  tiltZ: 0.05,  speed: 0.10, yLift: 0.45 },
  { count: 10, radius: 13.0, tiltX: 0.18,  tiltZ: 0.05,  speed: 0.07, yLift: 0.45 },
  { count: 10, radius: 16.0, tiltX: 0.18,  tiltZ: 0.05,  speed: 0.05, yLift: 0.45 },
];

function buildOrbitParams(count) {
  const params = [];
  let idx = 0;
  for (let r = 0; r < PHOTO_RINGS.length && idx < count; r++) {
    const ring = PHOTO_RINGS[r];
    const actualCount = Math.min(ring.count, count - idx);
    for (let i = 0; i < actualCount; i++) {
      params.push({
        orbitAngleOffset: (i / ring.count) * Math.PI * 2,
        radius: ring.radius,
        tiltX: ring.tiltX,
        tiltZ: ring.tiltZ,
        speed: ring.speed,
        yLift: ring.yLift,
        floatOffset: idx * 0.53,
      });
      idx++;
    }
  }
  // Overflow: extra ring
  while (idx < count) {
    params.push({
      orbitAngleOffset: ((idx % 10) / 10) * Math.PI * 2,
      radius: 19.0,
      tiltX: 0.18,
      tiltZ: 0.05,
      speed: 0.04,
      yLift: 0.45,
      floatOffset: idx * 0.53,
    });
    idx++;
  }
  return params;
}

function useOrbitalPosition(orbit, meshRef, materialRef) {
  useFrame((state) => {
    if (!meshRef.current) return;
    const t = state.clock.elapsedTime;
    const angle = orbit.orbitAngleOffset + t * orbit.speed;

    // Flat ring position
    const x = Math.cos(angle) * orbit.radius;
    const z = Math.sin(angle) * orbit.radius;

    // Apply tilt (same math as particle rings so photos sit ON the ring)
    const cosX = Math.cos(orbit.tiltX), sinX = Math.sin(orbit.tiltX);
    const cosZ = Math.cos(orbit.tiltZ), sinZ = Math.sin(orbit.tiltZ);

    const rx = x * cosZ - z * sinZ;
    const ry = (x * sinZ + z * cosZ) * sinX;
    const rz = (x * sinZ + z * cosZ) * cosX;

    // Lift photos above the ring plane + gentle float
    meshRef.current.position.set(
      rx,
      ry + orbit.yLift + Math.sin(t * 0.6 + orbit.floatOffset) * 0.15,
      rz
    );

    // Face outward from center (billboard toward camera is handled by OrbitControls)
    meshRef.current.rotation.y = -angle + Math.PI * 0.5;
    // Tilt to lie slightly on the ring plane
    meshRef.current.rotation.x = orbit.tiltX * 0.6;

    // Fade when passing "behind" — vanish every 2 full orbits
    if (materialRef?.current) {
      const fadeVal = Math.sin(angle * 0.5);
      const targetOpacity = fadeVal < -0.65
        ? Math.max(0, 1 - (Math.abs(fadeVal) - 0.65) / 0.35)
        : 1.0;
      materialRef.current.opacity = THREE.MathUtils.lerp(
        materialRef.current.opacity, targetOpacity, 0.07
      );
    }
  });
}

function RealPhotoCard({ url, orbit, onClick }) {
  const meshRef = useRef();
  const materialRef = useRef();
  const [hovered, setHovered] = useState(false);
  const texture = useTexture(url);
  useOrbitalPosition(orbit, meshRef, materialRef);

  return (
    <mesh
      ref={meshRef}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.3 : 1}
    >
      <planeGeometry args={[1.6, 1.15]} />
      <meshStandardMaterial
        ref={materialRef}
        map={texture}
        side={THREE.DoubleSide}
        transparent
        opacity={1}
      />
    </mesh>
  );
}

function ColorCard({ color, orbit, index, onClick }) {
  const meshRef = useRef();
  const materialRef = useRef();
  const [hovered, setHovered] = useState(false);
  const threeColor = useMemo(() => new THREE.Color(color), [color]);
  useOrbitalPosition(orbit, meshRef, materialRef);

  return (
    <mesh
      ref={meshRef}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.3 : 1}
    >
      <planeGeometry args={[1.6, 1.15]} />
      <meshStandardMaterial
        ref={materialRef}
        color={threeColor}
        emissive={threeColor}
        emissiveIntensity={0.5}
        side={THREE.DoubleSide}
        transparent
        opacity={1}
      />
    </mesh>
  );
}

function PhotoCard({ photo, orbit, index, onClick }) {
  const isColor = photo.startsWith('__color__');
  if (isColor) {
    return <ColorCard color={photo.replace('__color__', '')} orbit={orbit} index={index} onClick={onClick} />;
  }
  return <RealPhotoCard url={photo} orbit={orbit} onClick={onClick} />;
}

// ─────────────────────────────────────────────
// MAIN EXPORT — rings + photos
// ─────────────────────────────────────────────
export default function PhotoStars({ photos, onPhotoClick }) {
  const orbitParams = useMemo(() => buildOrbitParams(photos.length), [photos.length]);

  // Saturn particle rings — match photo ring radii closely
  const particleRings = [
    { inner: 4.5,  outer: 7.0,  tiltX: 0.18, tiltZ: 0.0,  count: 1800, color: '#c8b8ff' },
    { inner: 6.8,  outer: 9.5,  tiltX: 0.18, tiltZ: 0.05, count: 2200, color: '#b8d4ff' },
    { inner: 9.0,  outer: 12.0, tiltX: 0.18, tiltZ: 0.05, count: 2600, color: '#ffd4f0' },
    { inner: 11.5, outer: 14.5, tiltX: 0.18, tiltZ: 0.05, count: 2800, color: '#ffe8b8' },
    { inner: 14.0, outer: 18.0, tiltX: 0.18, tiltZ: 0.05, count: 3000, color: '#d4ffee' },
  ];

  return (
    <group>
      {/* Saturn-style particle rings */}
      {particleRings.map((ring, i) => (
        <SaturnRing key={i} {...ring} particleCount={ring.count} />
      ))}

      {/* Photos floating above the rings */}
      {photos.map((photo, i) => (
        <PhotoCard
          key={i}
          photo={photo}
          orbit={orbitParams[i]}
          index={i}
          onClick={() => onPhotoClick(photo, i)}
        />
      ))}
    </group>
  );
}
